#include<bits/stdc++.h>
using namespace std;
long long n,s,st[5050],sf[5050],t[5050],f[5050],dp[5050];
int main()
{
    scanf("%lld%lld",&n,&s);
    for(long long i=1;i<=n;i++)
    {
        scanf("%lld%lld",&t[i],&f[i]);
        st[i]=st[i-1]+t[i];
        sf[i]=sf[i-1]+f[i];
    }
    memset(dp,0x3f,sizeof(dp));
    dp[0]=0;
    for(long long i=1;i<=n;i++)
    {
        for(long long j=1;j<=i;j++)
        {
            dp[i]=min(dp[i],dp[j-1]+st[i]*(sf[i]-sf[j-1])+(sf[n]-sf[j-1])*s);
        }
    }
    printf("%lld",dp[n]);
    return 0;
}
